// Get all Drive files
const driveFiles = $('List quote images from Drive').all().map(i => i.json);
const allImages = driveFiles.filter(f => f.mimeType && f.mimeType.startsWith('image/'));

// Get already-used file IDs from Sheets
const usedRows = $('Read used quotes from Sheets').all().map(i => i.json);
const usedIds = new Set(usedRows.map(r => r.drive_file_id).filter(Boolean));

// Filter to unused
const unused = allImages.filter(f => !usedIds.has(f.id));
if (unused.length === 0) throw new Error('No unused quote images left in Drive folder!');

// Pick up to 7 (or fewer if not enough)
const pick = unused.slice(0, 7);

// Build voice memory from top posts
const topPosts = $('Read top performing posts').all().map(i => i.json);
const voiceExamples = topPosts
  .filter(p => p.approved_variant && p['variant_' + p.approved_variant.toLowerCase() + '_ig_caption'])
  .slice(0, 5)
  .map(p => ({
    caption: p['variant_' + p.approved_variant.toLowerCase() + '_ig_caption'],
    eng_rate: p.ig_eng_rate,
    format: p.format,
    pillar: p.pillar
  }));

// Calculate next Monday
const today = new Date();
const dayOfWeek = today.getDay();
const daysUntilMonday = dayOfWeek === 0 ? 1 : (8 - dayOfWeek);
const monday = new Date(today);
monday.setDate(today.getDate() + daysUntilMonday);

// Build schedule dates
const scheduleDates = pick.map((file, i) => {
  const d = new Date(monday);
  d.setDate(monday.getDate() + i);
  return d.toISOString().split('T')[0];
});

return pick.map((file, i) => ({
  json: {
    fileId: file.id,
    fileName: file.name,
    mimeType: file.mimeType,
    scheduledDate: scheduleDates[i],
    dayIndex: i,
    voiceMemory: JSON.stringify(voiceExamples)
  }
}));

const binaryData = $input.first().binary;
const binaryKey = Object.keys(binaryData)[0];
const mimeType = binaryData[binaryKey].mimeType || 'image/png';
const base64Data = binaryData[binaryKey].data;

// Pass through all metadata from previous node
const meta = $('Pick 7 unused images + build voice context').item.json;

return [{ json: {
  base64Image: base64Data,
  mimeType: mimeType,
  fileId: meta.fileId,
  fileName: meta.fileName,
  scheduledDate: meta.scheduledDate,
  voiceMemory: meta.voiceMemory
}}];

