const response = $input.first().json;
const rawText = response.content[0].text;

let parsed;
try {
  const cleaned = rawText.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(err) {
  throw new Error('Claude JSON parse failed. Raw: ' + rawText.substring(0, 300));
}

const meta = $('Convert image to base64').item.json;

return [{ json: {
  row_id: 'post_' + Date.now(),
  quote_text: parsed.quote_extracted,
  pillar: parsed.pillar,
  format: parsed.variant_a.format,
  scheduled_date: meta.scheduledDate,
  drive_file_id: meta.fileId,
  status: 'pending_approval',
  variant_a_svg_feed: parsed.variant_a.svg_feed,
  variant_a_svg_story: parsed.variant_a.svg_story,
  variant_a_ig_caption: parsed.variant_a.ig_caption,
  variant_a_li_caption: parsed.variant_a.li_caption,
  variant_a_format: parsed.variant_a.format,
  variant_b_svg_feed: parsed.variant_b.svg_feed,
  variant_b_svg_story: parsed.variant_b.svg_story,
  variant_b_ig_caption: parsed.variant_b.ig_caption,
  variant_b_li_caption: parsed.variant_b.li_caption,
  variant_b_format: parsed.variant_b.format,
  variant_c_svg_feed: parsed.variant_c.svg_feed,
  variant_c_svg_story: parsed.variant_c.svg_story,
  variant_c_ig_caption: parsed.variant_c.ig_caption,
  variant_c_li_caption: parsed.variant_c.li_caption,
  variant_c_format: parsed.variant_c.format
}}];

const rows = $input.all();
if (rows.length === 0) return []; // already approved, skip

const post = rows[0].json;

// Trigger the posting flow by calling Workflow 3 internally via HTTP
// (or duplicate the render+post logic here)
return [{ json: {
  row_id: post.row_id,
  approved_variant: 'a',
  auto_approved: true,
  svg_feed: post.variant_a_svg_feed,
  svg_story: post.variant_a_svg_story,
  ig_caption: post.variant_a_ig_caption,
  li_caption: post.variant_a_li_caption
}}];

const body = $input.first().json.body || $input.first().json.Body || '';
const from = $input.first().json.from || $input.first().json.From || '';
const reply = body.trim();

// Only process replies from Anisa's number
const anisaNumber = $vars.ANISA_WHATSAPP_NUMBER.replace('whatsapp:', '');
if (!from.includes(anisaNumber.replace('+', ''))) {
  return [{ json: { skip: true, reason: 'message not from Anisa' } }];
}

const valid = ['0', '1', '2', '3'];
if (!valid.includes(reply)) {
  return [{ json: { skip: true, reason: 'not a valid reply (must be 0-3)' } }];
}

return [{ json: { reply, variantKey: reply === '1' ? 'a' : reply === '2' ? 'b' : reply === '3' ? 'c' : null, skip: reply === '0' } }];

const post = $('Get today\'s pending post').first().json;
const v = $('Parse reply number').first().json.variantKey;

const svgFeed = post['variant_' + v + '_svg_feed'];
const svgStory = post['variant_' + v + '_svg_story'];
const igCaption = post['variant_' + v + '_ig_caption'];
const liCaption = post['variant_' + v + '_li_caption'];

return [{ json: {
  row_id: post.row_id,
  approved_variant: v,
  svg_feed: svgFeed,
  svg_story: svgStory,
  ig_caption: igCaption,
  li_caption: liCaption,
  quote_text: post.quote_text,
  pillar: post.pillar
}}];

const igData = $('Fetch Instagram insights').item.json.data || [];
const liData = $('Fetch LinkedIn insights').item.json;

// Parse IG metrics
const igMetrics = {};
for (const m of igData) igMetrics[m.name] = m.values?.[0]?.value || 0;

const igLikes = igMetrics['likes'] || 0;
const igComments = igMetrics['comments'] || 0;
const igSaves = igMetrics['saved'] || 0;
const igReach = igMetrics['reach'] || 1;
const igImpressions = igMetrics['impressions'] || 0;
const igEngRate = ((igLikes + igComments + igSaves) / igReach * 100).toFixed(2);

// Parse LI metrics
const liReactions = liData?.likesSummary?.totalLikes || 0;
const liComments = liData?.commentsSummary?.totalFirstLevelComments || 0;
const liImpressions = liData?.totalShareStatistics?.impressionCount || 0;

return [{ json: {
  row_id: $('Read Sheets for target date').item.json.row_id,
  ig_likes: igLikes,
  ig_comments: igComments,
  ig_saves: igSaves,
  ig_reach: igReach,
  ig_impressions: igImpressions,
  ig_eng_rate: parseFloat(igEngRate),
  li_reactions: liReactions,
  li_comments: liComments,
  li_impressions: liImpressions
}}];

const now = new Date();
const firstOfLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const firstOfThisMonth = new Date(now.getFullYear(), now.getMonth(), 1);

const rows = $input.all().map(i => i.json)
  .filter(r => {
    const d = new Date(r.scheduled_date);
    return d >= firstOfLastMonth && d < firstOfThisMonth && r.status === 'posted';
  });

if (rows.length === 0) return [{ json: { error: 'No posts found for last month' } }];

// Sort by engagement rate
const sorted = [...rows].sort((a, b) => (parseFloat(b.ig_eng_rate) || 0) - (parseFloat(a.ig_eng_rate) || 0));
const top3 = sorted.slice(0, 3);

// Pillar breakdown
const pillarMap = {};
for (const r of rows) {
  pillarMap[r.pillar] = pillarMap[r.pillar] || { count: 0, total_eng: 0 };
  pillarMap[r.pillar].count++;
  pillarMap[r.pillar].total_eng += parseFloat(r.ig_eng_rate) || 0;
}
const pillarStats = Object.entries(pillarMap).map(([p, s]) => ({
  pillar: p, count: s.count, avg_eng: (s.total_eng / s.count).toFixed(2)
})).sort((a, b) => b.avg_eng - a.avg_eng);

// Format breakdown
const formatMap = {};
for (const r of rows) {
  formatMap[r.format] = formatMap[r.format] || { count: 0, total_eng: 0 };
  formatMap[r.format].count++;
  formatMap[r.format].total_eng += parseFloat(r.ig_eng_rate) || 0;
}
const formatStats = Object.entries(formatMap).map(([f, s]) => ({
  format: f, count: s.count, avg_eng: (s.total_eng / s.count).toFixed(2)
})).sort((a, b) => b.avg_eng - a.avg_eng);

const avgEngRate = (rows.reduce((s, r) => s + (parseFloat(r.ig_eng_rate) || 0), 0) / rows.length).toFixed(2);
const totalPosts = rows.length;
const totalReach = rows.reduce((s, r) => s + (parseInt(r.ig_reach) || 0), 0);
const totalSaves = rows.reduce((s, r) => s + (parseInt(r.ig_saves) || 0), 0);

const monthName = firstOfLastMonth.toLocaleDateString('en-GB', { month: 'long', year: 'numeric' });

return [{ json: {
  monthName,
  totalPosts,
  avgEngRate,
  totalReach,
  totalSaves,
  top3: JSON.stringify(top3),
  pillarStats: JSON.stringify(pillarStats),
  formatStats: JSON.stringify(formatStats),
  allPostsSummary: JSON.stringify(rows.map(r => ({
    date: r.scheduled_date,
    pillar: r.pillar,
    format: r.format,
    ig_eng_rate: r.ig_eng_rate,
    ig_saves: r.ig_saves,
    ig_reach: r.ig_reach,
    li_reactions: r.li_reactions,
    quote: r.quote_text?.substring(0, 80)
  })))
}}];

